// Get weather icon based on WeatherAPI condition code
inline const lv_img_dsc_t* getWeatherIconBitmap(int code, bool is_day) {
    switch (code) {
        case 1000: return is_day ? &img_sunny : &img_cloudy;
        case 1003: return &img_partly_cloudy;
        case 1006: case 1009: return &img_cloudy;
        case 1030: case 1135: case 1147: return &img_foggy;
        case 1063: case 1150: case 1153: case 1180: case 1183:
        case 1186: case 1189: case 1240: return &img_rainy;
        case 1192: case 1195: case 1243: case 1246: return &img_rainy;
        case 1066: case 1114: case 1210: case 1213: case 1216:
        case 1219: case 1222: case 1225: case 1255: case 1258:
        case 1117: case 1261: case 1264: return &img_snow;
        case 1069: case 1072: case 1168: case 1171: case 1198:
        case 1201: case 1204: case 1207: case 1237: case 1249:
        case 1252: return &img_sleet;
        case 1087: case 1273: case 1276: case 1279: case 1282:
            return &img_storm;
        default: return &img_cloudy;
    }
}

